from datetime import date

def effective_deadline(crqc_year: int, sensitivity_years: int) -> int:
    return crqc_year - sensitivity_years

def exposure_status(transmission_year: int,
                    sensitivity_years: int,
                    crqc_year: int = 2040) -> dict:
    sensitive_until = transmission_year + sensitivity_years
    at_risk = sensitive_until > crqc_year

    if at_risk:
        exposure_years = sensitive_until - crqc_year
        if exposure_years > 10:
            status = 'critical'
        elif exposure_years > 5:
            status = 'high_risk'
        else:
            status = 'at_risk'
    else:
        exposure_years = 0
        status = 'safe'

    return {
        'sensitive_until': sensitive_until,
        'at_risk': at_risk,
        'exposure_years': exposure_years,
        'status': status
    }

def analyze_data_portfolio(data_items: list, crqc_year: int = 2040) -> dict:
    results = []

    for item in data_items:
        status = exposure_status(
            item['transmission_year'],
            item['sensitivity_years'],
            crqc_year
        )
        status['name'] = item['name']
        results.append(status)

    # Sort by risk (critical first)
    risk_order = {'critical': 0, 'high_risk': 1, 'at_risk': 2, 'safe': 3}
    results.sort(key=lambda x: (risk_order[x['status']], -x['exposure_years']))

    # Count by status
    counts = {}
    for r in results:
        counts[r['status']] = counts.get(r['status'], 0) + 1

    return {
        'items': results,
        'counts': counts,
        'total': len(results),
        'at_risk_count': sum(1 for r in results if r['at_risk'])
    }

def assess_threat_actor_capability(actor_type: str) -> dict:
    capabilities = {
        'nation_state': {
            'collection_capability': 10,
            'storage_capacity': 10,
            'patience': 10,
            'motivation': 9,
            'resources': 10
        },
        'state_sponsored': {
            'collection_capability': 8,
            'storage_capacity': 7,
            'patience': 8,
            'motivation': 8,
            'resources': 7
        },
        'criminal': {
            'collection_capability': 5,
            'storage_capacity': 4,
            'patience': 3,
            'motivation': 6,
            'resources': 4
        },
        'insider': {
            'collection_capability': 6,
            'storage_capacity': 3,
            'patience': 4,
            'motivation': 5,
            'resources': 2
        }
    }

    cap = capabilities.get(actor_type, capabilities['criminal'])
    cap['overall_threat'] = sum(cap.values()) / len(cap)
    cap['actor_type'] = actor_type

    return cap

def organizational_target_value(org_type: str, data_types: list) -> dict:
    org_values = {
        'government': 10,
        'defense': 10,
        'healthcare': 7,
        'financial': 8,
        'tech': 7,
        'retail': 4
    }

    data_values = {
        'classified': 10,
        'pii': 7,
        'financial': 8,
        'trade_secrets': 8,
        'medical': 7,
        'operational': 4
    }

    org_score = org_values.get(org_type, 5)
    data_score = max(data_values.get(d, 3) for d in data_types) if data_types else 3

    return {
        'org_type': org_type,
        'org_value': org_score,
        'data_value': data_score,
        'overall_target_value': (org_score + data_score) / 2
    }

def hndl_threat_matrix(org_profile: dict) -> dict:
    target = organizational_target_value(
        org_profile.get('type', 'unknown'),
        org_profile.get('data_types', [])
    )

    adversary_assessments = []
    for adv in org_profile.get('adversaries', ['criminal']):
        cap = assess_threat_actor_capability(adv)
        risk_score = cap['overall_threat'] * target['overall_target_value'] / 10
        adversary_assessments.append({
            'adversary': adv,
            'capability': cap['overall_threat'],
            'target_value': target['overall_target_value'],
            'risk_score': risk_score
        })

    adversary_assessments.sort(key=lambda x: x['risk_score'], reverse=True)

    return {
        'organization': target,
        'adversary_risks': adversary_assessments,
        'highest_risk': adversary_assessments[0] if adversary_assessments else None,
        'recommendation': 'URGENT PQC Migration' if any(a['risk_score'] > 7 for a in adversary_assessments) else 'Standard Migration'
    }
